var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"전방 11시 방향! 소형 침식체 다수의 접근 확인했습니다!","JPN":"前方、11時の方角！　多数の小型侵食体が接近中です！","ENG":"Multiple small C.O.s approaching from eleven o'clock!","TWN":"前方十一點鐘方向！確認有多個小型侵蝕體正在靠近！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"속도를 늦추지 마! 내가 처리하겠다!","JPN":"このまま前進！　私が処理する！","ENG":"Don't slow down! I'll handle them!","TWN":"不要減速！我來處理！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"목표가 코앞이니, 다들 전진하도록!!","JPN":"目標が目の前にいる、みんな進め！！","ENG":"We're right on top of the target. Keep moving forward!","TWN":"目標就在眼前，大家繼續前進！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"어떻게 된 거야? 지금 단장은 버고 소드가 없는 거 아니었어?","JPN":"どうなってるの？　今の団長って、ヴァルゴソードがないんじゃなかったの？","ENG":"Wait, isn't Captain fighting without the Virgo Sword?!","TWN":"怎麼回事？團長現在不是沒有布林加夫之劍嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"움직임만 보면 이전보다 강해진 것 같은데?","JPN":"動きを見ると、前より強くなった気がするけど。","ENG":"She actually seems stronger than before.","TWN":"從動作來看，好像比以前更強了？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"이전에도 군더더기 없는 움직임이었으나, 지금은 마치 검과 하나된 듯 보이는군요.","JPN":"前にも無駄な動きはなかったのですが、今はまるで剣と一つになっているようです。","ENG":"Her movements were already clean before, but now she fights as though she's become one with her blade.","TWN":"之前的動作已經很乾淨俐落了，現在看起來就像與劍融為一體一樣。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"ですが……","ENG":"But still...","TWN":"但是……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"크윽!","JPN":"くっ！","ENG":"Kgh!","TWN":"呃！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"공방일체를 추구한다는 점은 레온하르트 경과 같으나, 기교는 턱없이 부족하군.","JPN":"攻防一体を追求しているところはレオンハルト卿と同じだが、テクニックはまだまだ足りない。","ENG":"Your unity of attack and defense may mirror Dame Leonhardt's, but you sorely lack finesse.","TWN":"雖然追求攻防一體的理念與里恩哈特相同，但技巧卻遠遠不足。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"고작 이런 실력으로 기사도를 운운한 건가?","JPN":"たかがこのような実力で騎士道を口にしたのか？","ENG":"And with that level of skill, you dare speak of chivalry?","TWN":"就憑這種實力，也敢談論騎士精神嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"1시 방향! 대, 대형 침식체 반응입니다!","JPN":"1時の方角！　お、大型侵食体の反応です！","ENG":"Large C.O. detected at one o'clock!","TWN":"1點鐘方向！大，大型侵蝕體反應！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"갑자기 저것들이 대체 어디서……!!","JPN":"あいつら、いったいどこから……！！","ENG":"W-where are they coming from...?!","TWN":"那些東西突然從哪裡冒出來的……！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"소란 떨지 마라, 애송이들.","JPN":"騒ぐな。","ENG":"Calm down, kids.","TWN":"別鬧，小鬼。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"의식의 바라밀이 코앞이거늘, 무대 위 광대들이 실로 요란스럽군.","JPN":"儀式の波羅蜜が目前だというのに、舞台の上のピエロが実にうるさい。","ENG":"We're on the brink of enlightenment, and yet the jesters prance about the stage in chaos.","TWN":"意識的彼岸就在眼前，舞臺上的小丑們真是喧鬧不已。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"결국, 아셀라 경으로는 이정도가 한계인가?","JPN":"結局、アセッラ卿ではこれが限界か。","ENG":"So this is the extent of what Dame Ascella can offer?","TWN":"最終，亞瑟拉只能做到這種程度嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"카란티시르? 기척은 없었는데, 어떻게?","JPN":"カランティシル？　気配もなかったのに、どうやって？","ENG":"Carantisir?! I didn't sense anything, so how...?","TWN":"卡蘭堤西爾？沒有察覺到氣息，怎麼會這樣？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……이번에도 분신이군요.","JPN":"……今回も分身ですね。","ENG":"...Another clone.","TWN":"……這次也是分身嗎。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"역시, 경께서도 기사단을 홀로 상대하는 건 두려우신 겁니까?","JPN":"やはり、卿も一人で騎士団を相手するのが怖いのですか？","ENG":"Are you really so afraid of facing the Order alone?","TWN":"果然，你也害怕獨自面對騎士團嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"하하! 겁을 상실한 나머지 주제 파악조차 못하는 단계에 이르렀나?","JPN":"はは！　調子に乗りすぎて身の程知らずになったのか？","ENG":"Hah! Have you lost all sense of your place in this world?","TWN":"哈哈！你是不是已經到了失去恐懼，連自己處境都無法認清的地步了？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"너희 같은 쓰레기가 내 앞을 알짱거리는 것이 거슬릴 뿐이다.","JPN":"貴様らのようなクズが俺の前に立ちはだかるのが目障りなだけだ。","ENG":"Wretches like you getting in my way is what I find bothersome.","TWN":"像你們這樣的垃圾在我面前晃來晃去，真是礙眼。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"가치와 강함조차 없는 주제에, 내 계획을 일그러뜨리려는 그 알량한 태도도 말이지.","JPN":"価値も強さもない分際で、俺の計画を狂わせようとしているその傲慢な態度もな。","ENG":"You lack both value and strength, yet dare to disrupt my design with your petty resistance.","TWN":"連價值和力量都沒有，卻還想用那微不足道的態度來扭曲我的計畫。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"침식체들이 한 곳에 몰려 있는 걸 보면, 우리가 제대로 찾아온 것 같지?","JPN":"侵食体が一か所に集まってるところを見ると、私たち、ちゃんとたどり着いたんだよね？","ENG":"Seeing all the C.O.s clustered here means we're on the right track, huh?","TWN":"看這些侵蝕體聚集在一起，看來我們找對地方了吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"예. 앞으로 나가려면 저들을 뚫을 수밖에 없을 것 같군요.","JPN":"はい。前に進むためには、彼らを突破するしかなさそうです。","ENG":"Yes. If we want to advance, we'll have to cut through them.","TWN":"是的。要想前進，看來只能突破他們了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이 정도 병력이라면 아셀라라는 아이를 구할 수도 있었을 터.","JPN":"これくらいの兵力があれば、アセッラという子を救うこともできたはず。","ENG":"With this many forces, he could've saved that child, Ascella.","TWN":"以這樣的兵力，應該可以救出那個叫亞瑟拉的孩子。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"결국 마지막까지 동료가 아닌 자신의 안위만을 살피시는군요.","JPN":"結局、最後まで仲間ではなく自分の安全だけを気にしているのですね。","ENG":"But in the end, he only cared for his own safety, not his allies.","TWN":"最終到最後，你還是只關心自己的安危，而不是同伴。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그녀석은 처음부터 버리는 패였다.","JPN":"あいつは最初から捨て駒だった。","ENG":"She was a disposable pawn from the beginning.","TWN":"那傢伙從一開始就是棄子。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"제 주제를 모르고 전 세대의 기사를 둘이나 상대하려 했으니 패배는 예정된 수순이지.","JPN":"身の程も知らず、前の世代の騎士を2人も相手しようとしたのだ。敗北など、最初から決まっていた。","ENG":"Trying to take on two knights of the previous generation without knowing her limits. Her defeat was inevitable.","TWN":"不知天高地厚，竟敢挑戰兩位前代騎士，失敗是必然的結果。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……과거, 당신은 전임 기사단장과 함께 제게 우상과도 같은 존재였습니다.","JPN":"……過去、あなたは前騎士団長とともに私にとって憧れの存在でした。","ENG":"...You and the former captain were once heroes to me.","TWN":"……過去，你和前任騎士團團長曾是我心目中的偶像。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"대체 무슨 일이 있었길래 이렇게까지 변하신 거죠?","JPN":"いったいどうしてここまで変わってしまったのですか？","ENG":"What happened to you? How did you change so completely?","TWN":"到底發生了什麼事讓你變成這樣？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"당신에게 더 이상 기사도는 남아있지 않은 겁니까?","JPN":"あなたにはもう騎士道は残っていないのですか？","ENG":"Is there nothing left of your chivalry?","TWN":"難道你已經沒有騎士精神了嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"아니, 네놈들이 따르는 기사도 또한 타인이 정립시킨 것에 불과해.","JPN":"いや、貴様らが従っている騎士道もまた他人が作ったものに過ぎない。","ENG":"Your chivalry is nothing more than a doctrine crafted by others.","TWN":"不，你們所遵循的騎士精神也不過是別人制定的罷了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그 헐어버린 옛 규칙을 세계의 법칙에 따라 변화시킬 뿐이다.","JPN":"そのさびついた規則を、世界の法則に合わせて変化させるだけだ。","ENG":"I simply reshape those broken rules according to the world's true law.","TWN":"我只是按照世界的法則改變那些過時的舊規則而已。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"고리타분한 전통을 답습한 미래를, 네놈은 알고 있을 텐데?","JPN":"くだらない伝統を踏襲した未来を、貴様は知っているはずだが。","ENG":"Surely you've seen what future awaits if we blindly cling to old traditions.","TWN":"你應該知道，未來是沿襲陳腐的傳統的吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아니.","JPN":"いや。","ENG":"No.","TWN":"不。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"설령 그렇다 한들 네놈의 생각대로는 되지 않을 거다, 카란티시르.","JPN":"たとえそうだとしても、貴様の思いどおりにはさせない、カランティシル。","ENG":"Even if you're right, I refuse to let things unfold the way you want, Carantisir.","TWN":"即便如此，也不會如你所願，卡蘭堤西爾。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"흥. 책임 없는 말이라면 누구라도 가능하지.","JPN":"ふん。責任のない言葉なら誰でも発せられる。","ENG":"Hmph. Anyone can talk big when they're not accountable.","TWN":"哼。沒有責任的話，誰都能說。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"네놈이 옳다고 믿는 뜻을 관철하고 싶다면 어디 창칼로 입증해보도록.","JPN":"貴様が正しいと思うことを貫きたいのなら、武力で証明してみろ。","ENG":"If you really believe in your ideals, then prove them with your blade.","TWN":"如果你想貫徹你所認為的正確意志，那就用槍劍來證明吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"C, CSE 레벨이 급격하게 상승 중에 있습니다!","JPN":"C、CSEレベルが急激に上昇しています！","ENG":"C-CSE. levels are spiking rapidly!","TWN":"CSE等級正在急劇上升中！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"공간의 침식파가 개체 에너지와 반응 중! 이건, 설마…!!","JPN":"空間の侵食波が個体エネルギーと反応中！　これは、まさか……！！","ENG":"The Corruption ray is reacting with the entities' energy! It can't be...!!","TWN":"空間的侵蝕波正在與實體能量發生反應！這難道是…！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MONSTER_MOVEMENT_10"},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……도플갱어 신드롬.","JPN":"……ドッペルゲンガーシンドローム。","ENG":"...The Doppelganger syndrome.","TWN":"……二重身綜合症狀。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"구원기사단의 고유무장을 이용하여 일시적인 성역을 형성한 건가?","JPN":"救世騎士団の固有武装を利用して、一時的に聖域を形成したのか？","ENG":"They're using the Knights of Redemption's Unique Gear to create a temporary sanctuary?","TWN":"利用救贖騎士團的專屬武裝形成了暫時的聖域嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님. 싸움을 피할 순 없을 것 같습니다.","JPN":"団長。戦いは避けられなさそうです。","ENG":"Captain, we won't be able to avoid combat.","TWN":"團長。看來無法避免戰鬥了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이곳 너머에 카란티시르가 있는 건 확실하다. 그렇다면 망설일 필요는 없겠지.","JPN":"確かにこの向こうにはカランティシルがいる。ならば、戸惑う必要はない。","ENG":"Carantisir is just beyond here, I know it. So we have no reason to hesitate.","TWN":"可以確定卡蘭堤西爾就在這邊。那麼就沒有必要猶豫了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"조디악 나이츠! 대오를 갖춰라!","JPN":"ゾディアックナイツ！　隊列を整えろ！","ENG":"Zodiac Knights! Form ranks!","TWN":"十二宮騎士團！整隊！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"침식체들을 돌파해, 카란티시르를 추격한다!","JPN":"侵食体を突破し、カランティシルを追撃する！","ENG":"Break through the C.O.s and pursue Carantisir!","TWN":"突破侵蝕體，追擊卡蘭堤西爾！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};